// ========================================
// ১৮০ বার লুপের LIMIT কন্ট্রোল
// ========================================
const MAX_LOOP_LIMIT = 26;

// সব ইনপুট আইটেম নাও
const allItems = $input.all();

// মোট আইটেম সংখ্যা
const totalItems = allItems.length;

// ম্যাক্সিমাম ১৮০ পর্যন্ত সীমাবদ্ধ করো
const itemsToProcess = allItems.slice(0, MAX_LOOP_LIMIT);

console.log(`মোট ডাটা: ${totalItems} টি`);
console.log(`প্রসেস করা হবে: ${itemsToProcess.length} টি (সর্বোচ্চ ${MAX_LOOP_LIMIT})`);

// প্রতিটি আইটেমে loop_index এবং limit info যোগ করো
const processedItems = itemsToProcess.map((item, index) => {
  return {
    json: {
      ...item.json,
      loop_index: index + 1,
      loop_limit: MAX_LOOP_LIMIT,
      total_available: totalItems,
      is_last_item: index === itemsToProcess.length - 1
    }
  };
});

return processedItems;

// ========================================
// লুপ শেষে সারসংক্ষেপ
// ========================================
const items = $input.all();

console.log(`মোট ${items.length} টি আইটেম সফলভাবে প্রসেস হয়েছে`);

return [
  {
    json: {
      summary: `মোট ${items.length} টি আইটেম প্রসেস সম্পন্ন`,
      total_processed: items.length,
      completed_at: new Date().toISOString()
    }
  }
];

const attemptCount = $input.first().json['Attempt Count'];
const currentDate = DateTime.now().toFormat('MM/dd/yyyy');
const currentDate2 = DateTime.now().toFormat('MM/dd/yyyy');

const signature = `С уважением,
Елена
elena@imployii.com
Telegram: https://t.me/elenaiimp
WhatsApp: https://wa.me/48505340709`;

const daysToAdd = { 1: 2, 2: 5, 3: 10, 4: 10, 5: 60, 6: 62, 7: 65, 8: 70, 9: 80, 10: 90, 11: 92, 12: 95, 13: 100, 14: 110 };

// ── Next action date (based on currentDate2 + gap for current attempt) ──
const days = daysToAdd[attemptCount];
const nextDate = new Date(currentDate2);
nextDate.setDate(nextDate.getDate() + days);
const nextMonth = String(nextDate.getMonth() + 1).padStart(2, '0');
const nextDay   = String(nextDate.getDate()).padStart(2, '0');
const nextYear  = nextDate.getFullYear();
const nextActionDate = `${nextMonth}/${nextDay}/${nextYear}`;

// ── Legacy nextFollowUpDate (kept from original, uses currentDate) ──
const date = new Date(currentDate);
date.setDate(date.getDate() + days);
const month = String(date.getMonth() + 1).padStart(2, '0');
const day   = String(date.getDate()).padStart(2, '0');
const year  = date.getFullYear();
const formattedDate = `${month}/${day}/${year}`;

const messages = {
  1: {
    subject: "Найм иностранных сотрудников — как мы можем помочь",
    body: `Здравствуйте,

Надеюсь, это сообщение застанет вас в добром здравии.

Меня зовут Елена, я представляю компанию Imployii — мы специализируемся на помощи предприятиям в подборе квалифицированных иностранных работников для позиций в сфере производства, логистики и сервиса.

Мы берём на себя весь процесс подбора персонала и помогаем работодателям с оформлением необходимых документов, делая этот процесс максимально комфортным для вашей команды.

Если вы сейчас ищете сотрудников или открыты к рассмотрению такой возможности — я буду рада рассказать подробнее или договориться о коротком ознакомительном звонке.

${signature}`
  },
  2: {
    subject: "Напоминание о моём предыдущем письме",
    body: `Здравствуйте,

Хотела уточнить, удалось ли вам ознакомиться с моим предыдущим письмом о подборе персонала.

Сегодня многие компании решают проблему нехватки кадров за счёт найма иностранных работников, поэтому я решила написать повторно.

Подскажите, актуален ли для вас сейчас вопрос найма сотрудников?

${signature}`
  },
  3: {
    subject: "Как другие компании справляются с нехваткой персонала",
    body: `Здравствуйте,

Многие работодатели, с которыми мы сотрудничаем, сталкивались с той же проблемой — сложностью поиска надёжных местных сотрудников для производства, логистики и сферы услуг.

Начав работу с нами, они смогли быстро закрыть вакансии квалифицированными иностранными специалистами, пока мы занимались всеми документами на стороне работодателя.

Если это актуально для вас — я буду рада рассказать подробнее или организовать короткий звонок.

${signature}`
  },
  4: {
    subject: "Можем ли мы продвинуться с вопросом найма?",
    body: `Здравствуйте,

Хотела уточнить, актуален ли для вас сейчас вопрос подбора сотрудников.

При необходимости мы можем оперативно направить дополнительные резюме или скорректировать выборку кандидатов в соответствии с вашими текущими требованиями.

Пожалуйста, дайте знать, как вам удобнее действовать дальше. После выбора кандидатов работодателю необходимо подать приглашение — мы сопровождаем этот процесс на каждом этапе оформления документов.

${signature}`
  },
  5: {
    subject: "Стоит ли нам продолжать процесс подбора?",
    body: `Здравствуйте,

Я понимаю, что приоритеты компании могут меняться, поэтому хотела уточнить — стоит ли нам продолжать процесс подбора персонала?

Мы можем вернуться к этому в удобное для вас время, как только вопрос снова станет актуальным.

Буду рада оставаться на связи. После выбора кандидатов работодателю необходимо подать приглашение — мы сопровождаем этот процесс на каждом этапе оформления документов.

${signature}`
  },
  6: {
    subject: "Возвращаясь к теме — актуален ли сейчас найм?",
    body: `Здравствуйте,

Прошло некоторое время с нашего последнего общения, и я хотела написать ещё раз.

Потребности в персонале могут меняться быстро, и мы готовы помочь, как только для вас наступит подходящий момент.

Если вопрос подбора снова стал актуальным — я буду рада возобновить общение и обсудить, как мы можем поддержать вашу команду.

${signature}`
  },
  7: {
    subject: "Мы по-прежнему готовы помочь с подбором персонала",
    body: `Здравствуйте,

Хотела напомнить, что мы по-прежнему здесь и готовы помочь с вашими потребностями в подборе сотрудников.

Сейчас у нас есть квалифицированные кандидаты в сфере производства, логистики и услуг, готовые приступить к работе.

Если у вас есть открытые вакансии или вы ожидаете их появления в ближайшее время — сейчас хороший момент, чтобы начать процесс.

${signature}`
  },
  8: {
    subject: "Короткое обновление — новые кандидаты доступны",
    body: `Здравствуйте,

Хотела поделиться новостью — мы недавно пополнили нашу базу новыми кандидатами в нескольких отраслях, включая производство, логистику и сферу услуг.

Если вы хотите закрыть какие-либо позиции — мы можем сразу направить вам анкеты и оперативно пройти все этапы.

Дайте знать, если хотите ознакомиться.

${signature}`
  },
  9: {
    subject: "На связи — есть ли планы по найму в ближайшее время?",
    body: `Здравствуйте,

По мере того как год идёт вперёд, многие компании начинают планировать подбор персонала на предстоящие месяцы.

Хотела уточнить, есть ли у вас планы по найму, в реализации которых мы могли бы помочь.

Мы готовы сделать этот процесс максимально простым — от выбора кандидатов до полного сопровождения документации.

${signature}`
  },
  10: {
    subject: "Давно не общались — предлагаю возобновить контакт",
    body: `Здравствуйте,

Надеюсь, у вас всё хорошо.

Прошло уже немало времени с нашего последнего разговора, и я хотела написать ещё раз — чтобы узнать, стал ли вопрос найма иностранных работников актуальным для вашей компании.

Мы продолжаем работать с работодателями в различных отраслях и будем рады поддержать вас, когда возникнет такая необходимость.

${signature}`
  },
  11: {
    subject: "Мы по-прежнему готовы поддержать ваш подбор персонала",
    body: `Здравствуйте,

Хотела кратко написать, чтобы напомнить: наша команда по-прежнему полностью готова помочь с вашими кадровыми потребностями.

Нужен ли вам один человек или целая группа — мы можем адаптировать процесс подбора под ваши требования и сроки.

Обращайтесь в любое время — мы всегда рады помочь.

${signature}`
  },
  12: {
    subject: "Возможно, сейчас подходящий момент для найма?",
    body: `Здравствуйте,

Иногда всё дело в подходящем моменте, и я хотела ещё раз уточнить — не наступил ли он для вас.

Мы помогли многим компаниям в схожей ситуации быстро и без лишних сложностей начать процесс, и будем рады сделать то же самое для вас.

Если у вас есть даже небольшая потребность в персонале прямо сейчас — это повод для короткого разговора.

${signature}`
  },
  13: {
    subject: "Ещё одно сообщение, прежде чем я завершу переписку",
    body: `Здравствуйте,

Хотела написать ещё раз, прежде чем прекратить напоминать о себе.

Если найм иностранных работников на данном этапе не актуален для вашей компании — я прекрасно понимаю и не буду больше вас беспокоить.

Однако если есть хоть малейший шанс, что это может быть полезно — даже в ближайшей перспективе — я буду рада короткому разговору.

${signature}`
  },
  14: {
    subject: "Финальное сообщение — мы будем здесь, когда вы будете готовы",
    body: `Здравствуйте,

Это моё последнее сообщение на данный момент, и я хочу завершить его на позитивной ноте.

Если ваши потребности в найме когда-либо изменятся — пожалуйста, не стесняйтесь обращаться. Мы будем рады продолжить разговор в любое время.

Спасибо за ваше время, и желаю вам и вашей команде дальнейших успехов.

${signature}`
  }
};

const selected = messages[attemptCount];

if (!selected) {
  throw new Error(`No message defined for Attempt Count: ${attemptCount}`);
}

// ── Next attempt's subject & body (preview of what comes next) ──
const nextAttemptCount = attemptCount + 1;
const nextSelected = messages[nextAttemptCount] || null;

// Determine loop status for tracking
let loopStatus;
if (attemptCount <= 5) {
  loopStatus = 'loop_1';
} else if (attemptCount <= 10) {
  loopStatus = 'loop_2';
} else {
  loopStatus = 'loop_3';
}

return [{
  json: {
    subject: selected.subject,
    body: selected.body,
    attemptCount: attemptCount,
    nextActionDate: nextActionDate,
    nextActionSubject: nextSelected ? nextSelected.subject : null,
    nextActionBody: nextSelected ? nextSelected.body : null,
    nextFollowUpDate: formattedDate,
    loopStatus: loopStatus
  }
}];

// Per-lead eligibility check
const d = $input.first().json;
const today = new Date();
today.setHours(0,0,0,0);
const todayStr = today.toISOString().split('T')[0];
const leadId     = (d['Lead ID'] || '').toString().trim();
const status     = (d['Lead Status'] || '').toString().trim().toUpperCase();
const coolingRaw = d['Cooling Until'] ? d['Cooling Until'].toString().trim() : '';
const nextRaw    = d['Next Action Date'] ? d['Next Action Date'].toString().trim() : '';
const attempts   = parseInt(d['Attempt Count'] || 0);
const method     = (d['Preferred Contact Method'] || '').toString().trim().toUpperCase();
const phone      = (d['Phone Number'] || '').toString().trim();
const email      = (d['Email'] || '').toString().trim();

// Must have Lead ID
if (!leadId) return [{ json: { _skip: true, _reason: 'NO_LEAD_ID', ...d } }];

// Skip permanently closed
if (['DISQUALIFIED','CLOSED','QUALIFIED'].includes(status))
  return [{ json: { _skip: true, _reason: 'STATUS_CLOSED', ...d } }];

// Cooling period guard
if (coolingRaw) {
  const cooling = new Date(coolingRaw);
  cooling.setHours(0,0,0,0);
  if (cooling > today)
    return [{ json: { _skip: true, _reason: 'IN_COOLING', ...d } }];
}

// Max attempt guard
if (attempts >= 1000)
  return [{ json: { _skip: true, _reason: 'MAX_ATTEMPTS', ...d } }];

// Contact info guard
// if (method === 'PHONE' && !phone)
//   return [{ json: { _skip: true, _reason: 'NO_PHONE', ...d } }];
// if (['EMAIL','WHATSAPP','TELEGRAM'].includes(method) && !email && !phone)
//   return [{ json: { _skip: true, _reason: 'NO_CONTACT_INFO', ...d } }];

// NEW → always contact
if (status === 'NEW' || status === '') {
  return [{ json: { _skip: false, _eligibilityReason: 'NEW_LEAD', _today: todayStr, ...d } }];
}

// Other statuses → সবসময় contact
return [{ json: { _skip: false, _eligibilityReason: `STATUS_${status}`, _today: todayStr, ...d } }];

